// ChatTurnRequest One conversation turn from the browser. The message is free text and carries NO authority (PRD §8 free-text containment): it can never approve, execute, or confirm — those live only in structured controls outside the model plane. A turn optionally continues an existing conversation and/or binds a marketplace-account context; context resolution itself is deterministic in the LLM plane (§8.1), never guessed from this field.
type ChatTurnRequest struct {
	// Context The deterministic context a turn binds to the conversation (PRD §8.1 CHAT-007). Route entry and structured picker selection BIND the selected entity here so the gateway persists the exact kind/entity the operator sees — the chip can never claim a context the gateway did not receive. Binding is SERVER-VERSIONED and APPEND-ONLY: the first turn establishes version 1; changing the bound entity requires an EXPLICIT transition (`transition: true`) that appends a new version, never a silent relabel; a `contextVersion` that no longer matches the conversation's current bound version is REJECTED (stale) and produces no Draft. Account, context entity, and conversation provenance must belong to the same tenant.
	Context *ConversationContextBinding `json:"context,omitempty"`

	// ConversationId Existing conversation to continue. Absent on the first turn; the gateway opens a new conversation and returns its id in the stream.
	ConversationId *openapi_types.UUID `json:"conversationId,omitempty"`

	// Locale The active application locale this turn is authored in (LOC-001/LOC-007). REQUIRED and carried on EVERY turn: input digit-family normalization makes Persian and Latin digits identical on the wire, so the locale can NEVER be recovered from the message text, digit shape, region, or account default — this field is the ONLY authoritative locale signal. Locale is DATA, not inferred: the gateway validates it against the closed supported set and FAILS CLOSED (canonical 4xx) on an unknown or missing value, and binds/versions it on the conversation. It carries no approval authority.
	Locale SupportedLocale `json:"locale"`

	// LocaleTransition Set true to EXPLICITLY transition the conversation's bound locale to a different value (appends a new locale version). Without it, a turn whose `locale` differs from the conversation's current bound locale is rejected rather than silently relabeling the conversation — a same-locale continuation is idempotent and needs neither this flag nor a version.
	LocaleTransition *bool `json:"localeTransition,omitempty"`

	// LocaleVersion The conversation's locale-binding version this turn is issued against (mirrors `contextVersion`, CHAT-007). Absent on the first turn (the gateway issues version 1). On a continuation whose `locale` differs from the conversation's current bound locale it must equal the current bound version; a stale/mismatched version is rejected without producing a Draft.
	LocaleVersion *int32 `json:"localeVersion,omitempty"`

	// MarketplaceAccountId Optional account context for the turn. Exactly one context is active per conversation; ambiguity is resolved by a structured picker, never inferred (CHAT-007).
	MarketplaceAccountId *openapi_types.UUID `json:"marketplaceAccountId,omitempty"`

	// Message The user's free-text message. Bounded; carries no authority.
	Message string `json:"message"`
}

